// 创建CSV内容
const issns = $input.item.json.issns;
const csvHeader = "ISSN";
const csvRows = issns.join('\n');
const csvContent = `${csvHeader}\n${csvRows}`;

// 创建文件名
const outputFilename = $input.item.json.outputFilename;
const csvFilename = `${outputFilename}.csv`;

// 保存查询语句
const query = $input.item.json.originalQuery;
const queryFilename = `${outputFilename}_core_query.txt`;

// 转换CSV内容为二进制
const binaryData = {
  data: Buffer.from(csvContent).toString('base64'),
  mimeType: 'text/csv',
  fileName: csvFilename
};

return {
  json: {
    issns,
    csvContent,
    csvFilename,
    queryContent: query,
    queryFilename,
    issnsCount: $input.item.json.issnsCount
  },
  binary: {
    data: binaryData
  }
};

