// 合并所有文章的ISSN
const items = $input.all();
const issnList = [];

// 收集所有ISSN
for (const item of items) {
  if (item.json.issn && item.json.issn !== 'N/A' && item.json.issn !== null) {
    issnList.push(item.json.issn);
  }
}

// 去重
const uniqueIssnList = [...new Set(issnList)];

// 获取时间戳和输出文件名（添加时分秒）
const now = new Date();
const year = now.getFullYear();
const month = String(now.getMonth() + 1).padStart(2, '0');
const day = String(now.getDate()).padStart(2, '0');
const hours = String(now.getHours()).padStart(2, '0');
const minutes = String(now.getMinutes()).padStart(2, '0');
const seconds = String(now.getSeconds()).padStart(2, '0');
const timestamp = `${year}${month}${day}_${hours}${minutes}${seconds}`;
const outputFilename = `retrieved_issns(${timestamp})`;

// 原始查询
// 注意: 这里修改为从生成PubMed检索式节点获取，或者创建一个默认值
const originalQuery = $node["生成PubMed检索式"]?.json?.output || "No query available";

// 返回结果
return {
  issns: uniqueIssnList,
  issnsCount: uniqueIssnList.length,
  timestamp,
  outputFilename,
  originalQuery
};

// 获取上一步传入的单篇文章数据
const articleJson = $json;

// --- 提取 PMID ---
let pmid = null;
try {
    const pmidSource = articleJson.MedlineCitation?.PMID;
    pmid = pmidSource?._ ?? pmidSource ?? null;
} catch (error) {
    console.error(`!!! Error extracting PMID for item ${$itemIndex}:`, error);
}

// --- 提取 Title ---
let title = null;
try {
    const titleSource = articleJson.MedlineCitation?.Article?.ArticleTitle;
    title = titleSource?._ ?? titleSource ?? null;
    if (typeof title === 'object' && title !== null && title._) {
        title = title._;
    }
} catch (error) {
    console.error(`!!! Error extracting Title for item ${$itemIndex}:`, error);
}

// --- 提取 Abstract ---
let abstractText = null;
try {
  const abstractDataSource = articleJson.MedlineCitation?.Article?.Abstract?.AbstractText;
  if (abstractDataSource) {
    if (Array.isArray(abstractDataSource)) {
      abstractText = abstractDataSource.map(item => {
        let textPart = '';
        if (typeof item === 'object' && item !== null) {
          const label = item.Label;
          const text = item._;
          textPart = (label ? `[${label}] ` : '') + (text || '');
        } else if (typeof item === 'string') {
          textPart = item;
        }
        return textPart;
      }).filter(s => s).join('\n\n');
    } else if (typeof abstractDataSource === 'string') {
      abstractText = abstractDataSource;
    } else if (typeof abstractDataSource === 'object' && abstractDataSource !== null) {
       const label = abstractDataSource.Label;
       const text = abstractDataSource._;
       abstractText = (label ? `[${label}] ` : '') + (text || '');
    }
  }
} catch (error) {
  console.error(`!!! Error extracting abstract for item ${$itemIndex}:`, error);
}

// --- 提取作者相关信息 ---
let firstAuthorName = null;
let firstAuthorAffiliation = null;
let correspondingAuthorName = null;
try {
  const authors = articleJson.MedlineCitation?.Article?.AuthorList?.Author;
  if (Array.isArray(authors) && authors.length > 0) {
    const firstAuthor = authors[0];
    if (firstAuthor) {
      const fName = firstAuthor.ForeName || '';
      const lName = firstAuthor.LastName || '';
      firstAuthorName = `${fName} ${lName}`.trim() || null;
      const firstAffInfo = Array.isArray(firstAuthor.AffiliationInfo) ? firstAuthor.AffiliationInfo[0] : firstAuthor.AffiliationInfo;
      if (firstAffInfo?.Affiliation) {
          firstAuthorAffiliation = firstAffInfo.Affiliation._ ?? firstAffInfo.Affiliation ?? null;
      }
    }
    const lastAuthor = authors[authors.length - 1];
    if (lastAuthor) {
      if (lastAuthor.CollectiveName) {
         correspondingAuthorName = lastAuthor.CollectiveName._ ?? lastAuthor.CollectiveName ?? null;
      } else {
         const fName = lastAuthor.ForeName || '';
         const lName = lastAuthor.LastName || '';
         correspondingAuthorName = `${fName} ${lName}`.trim() || null;
      }
    }
  }
} catch (error) {
  console.error(`!!! Error extracting author info for item ${$itemIndex}:`, error);
}

// --- 提取杂志名称 ---
let journalName = null;
try {
    journalName = articleJson.MedlineCitation?.Article?.Journal?.Title;
} catch(error) {
    console.error(`!!! Error extracting journal name for item ${$itemIndex}:`, error);
}

// --- 提取并格式化发表日期 ---
let formattedPubDate = null;

// Helper function to format date parts
function formatDate(year, month, day) {
    const cleanYear = year ? String(year).match(/^\d{4}$/) ? String(year) : null : null;
    if (!cleanYear) return null;

    let cleanMonth = null;
    if (month) {
        const monthMap = {
            'Jan': '01', 'Feb': '02', 'Mar': '03', 'Apr': '04', 'May': '05', 'Jun': '06',
            'Jul': '07', 'Aug': '08', 'Sep': '09', 'Oct': '10', 'Nov': '11', 'Dec': '12'
        };
        let monthNumber = monthMap[month] || month;
        if (/^\d$/.test(monthNumber)) {
            monthNumber = '0' + monthNumber;
        }
        if (/^(0[1-9]|1[0-2])$/.test(monthNumber)) {
             cleanMonth = monthNumber;
        }
    }

    let cleanDay = null;
    if (day) {
       let dayNumber = String(day);
        if (/^\d$/.test(dayNumber)) {
            dayNumber = '0' + dayNumber;
        }
        if (/^(0[1-9]|[12]\d|3[01])$/.test(dayNumber)) {
             cleanDay = dayNumber;
        }
    }

    if (cleanYear && cleanMonth && cleanDay) {
        return `${cleanYear}-${cleanMonth}-${cleanDay}`;
    } else if (cleanYear && cleanMonth) {
        return `${cleanYear}-${cleanMonth}`;
    } else if (cleanYear) {
        return cleanYear;
    } else {
        return null;
    }
}

try {
    const pubDateObj = articleJson.MedlineCitation?.Article?.Journal?.JournalIssue?.PubDate;
    let formalYear = null, formalMonth = null, formalDay = null;
    let formalDateFormatted = null;

    if (pubDateObj) {
        formalYear = pubDateObj.Year?._ ?? pubDateObj.Year ?? null;
        formalMonth = pubDateObj.Month?._ ?? pubDateObj.Month ?? null;
        formalDay = pubDateObj.Day?._ ?? pubDateObj.Day ?? null;

        formalDateFormatted = formatDate(formalYear, formalMonth, formalDay);
        if (!formalDateFormatted || formalDateFormatted.length < 10) {
             formalDateFormatted = formatDate(formalYear, formalMonth, null) || formatDate(formalYear, null, null);
        }
        formattedPubDate = formalDateFormatted;
    }

    if (!formattedPubDate || formattedPubDate.length < 10) {
        const articleDates = articleJson.MedlineCitation?.Article?.ArticleDate;
        let epubDateObj = null;

        if (Array.isArray(articleDates)) {
            epubDateObj = articleDates.find(d => d?.DateType === 'Electronic');
        } else if (typeof articleDates === 'object' && articleDates !== null && articleDates.DateType === 'Electronic') {
            epubDateObj = articleDates;
        }

        if (epubDateObj) {
            const epubYear = epubDateObj.Year?._ ?? epubDateObj.Year ?? null;
            const epubMonth = epubDateObj.Month?._ ?? epubDateObj.Month ?? null;
            const epubDay = epubDateObj.Day?._ ?? epubDateObj.Day ?? null;

            const epubFormattedFull = formatDate(epubYear, epubMonth, epubDay);

            if (epubFormattedFull && epubFormattedFull.length === 10) {
                formattedPubDate = epubFormattedFull;
            } else if (!formattedPubDate) {
                 const epubFormattedPartial = formatDate(epubYear, epubMonth, null) || formatDate(epubYear, null, null);
                 if (epubFormattedPartial) {
                     formattedPubDate = epubFormattedPartial;
                 }
            }
        }
    }
} catch (error) {
    console.error(`!!! Error extracting/formatting publication date for item ${$itemIndex}:`, error);
    formattedPubDate = null;
}

// --- 格式化为适合综述生成的文本格式 ---
let formattedArticleText = '';

// 构建文献信息文本
formattedArticleText += `**文献 ${$itemIndex + 1}**\n`;
formattedArticleText += `**标题:** ${title || 'N/A'}\n`;
formattedArticleText += `**作者:** ${firstAuthorName || 'N/A'}`;
if (correspondingAuthorName && correspondingAuthorName !== firstAuthorName) {
    formattedArticleText += ` (第一作者), ${correspondingAuthorName} (通讯作者)`;
} else {
    formattedArticleText += ` (第一作者)`;
}
formattedArticleText += `\n`;
formattedArticleText += `**期刊:** ${journalName || 'N/A'}\n`;
formattedArticleText += `**发表时间:** ${formattedPubDate || 'N/A'}\n`;
if (firstAuthorAffiliation) {
    formattedArticleText += `**第一作者单位:** ${firstAuthorAffiliation}\n`;
}
formattedArticleText += `**PMID:** ${pmid || 'N/A'}\n`;
formattedArticleText += `**摘要:**\n${abstractText || 'N/A'}\n`;
formattedArticleText += `\n---\n`;

// --- 返回最终结果对象 ---
return {
  articleText: formattedArticleText,
  pmid: pmid,
  title: title,
  journal: journalName,
  authors: firstAuthorName,
  correspondingAuthor: correspondingAuthorName,
  affiliation: firstAuthorAffiliation,
  abstract: abstractText,
  publicationDate: formattedPubDate
};

// --- Part 1: 获取并处理 Markdown 文件内容 ---
const inputItem = $input.first(); // 获取 Code 节点自身的输入 (来自 Read File)
let markdownContent = "错误：无法读取 Markdown 文件内容。";
let extractedMarkdownContent = "错误：无法从 Markdown 内容中提取所需部分。";

// 检查并解码来自 Read File 节点的二进制数据
if (inputItem.binary && inputItem.binary.data && inputItem.binary.data.data) {
  try {
    const base64Data = inputItem.binary.data.data;
    markdownContent = Buffer.from(base64Data, 'base64').toString('utf8');

    // 提取三个反引号之间的内容
    const regex = /```([\s\S]*?)```/;
    const matchResult = markdownContent.match(regex);
    if (matchResult && matchResult[1]) {
      extractedMarkdownContent = matchResult[1].trim(); // 提取并去除前后空格
    } else {
      console.warn("未能从 Markdown 内容中找到 ```...``` 包裹的部分。");
      extractedMarkdownContent = "未找到被三个反引号包裹的内容。";
    }
  } catch (error) {
     console.error("解码或提取 Markdown 内容时出错:", error);
     // 如果出错，将错误信息设为提取内容，以便后续判断
     extractedMarkdownContent = `处理 Markdown 时出错: ${error.message}`;
  }
} else {
  console.warn("在上一个 Read/Write Files 节点的输出中未找到二进制数据。");
  extractedMarkdownContent = "错误：未找到 Markdown 文件内容数据。";
}

// --- Part 2: 获取“生成PubMed检索式”节点的输出 ---
let pubmedQuery = "错误：无法获取 PubMed 检索式。"; // 默认错误信息

try {
  // 使用 $node 表达式访问名为 "生成PubMed检索式" 的节点
  // 使用可选链 (?.) 防止节点或属性不存在时报错
  // Agent 节点的输出通常在 json.output
  const pubmedNodeOutput = $node['生成PubMed检索式']?.json?.output;

  // 检查是否成功获取到输出
  if (pubmedNodeOutput !== undefined && pubmedNodeOutput !== null) {
    // 确保输出是字符串
    pubmedQuery = String(pubmedNodeOutput);
  } else {
     console.warn("未能从'生成PubMed检索式'节点获取有效的输出 (json.output)。");
     // pubmedQuery 保持为错误信息
  }
} catch (error) {
  console.error("访问'生成PubMed检索式'节点输出时出错:", error);
  // 如果访问节点本身出错，pubmedQuery 保持为错误信息
  pubmedQuery = `访问 PubMed 检索式节点时出错: ${error.message}`;
}


// --- Part 3: 组合两部分内容 ---
let finalOutputText = "";

// 检查两部分内容是否都有效（即不是错误信息）
const isMarkdownValid = !extractedMarkdownContent.startsWith("错误：") && extractedMarkdownContent !== "未找到被三个反引号包裹的内容。";
const isQueryValid = !pubmedQuery.startsWith("错误：") && !pubmedQuery.startsWith("访问 PubMed 检索式节点时出错:");

if (isMarkdownValid && isQueryValid) {
  // 如果两部分都有效，用 " AND " 连接
  finalOutputText = `${extractedMarkdownContent} AND ${pubmedQuery}`;
} else if (!isMarkdownValid) {
  // 如果 Markdown 内容无效，显示 Markdown 的错误信息
  finalOutputText = extractedMarkdownContent;
} else {
  // 如果 PubMed Query 无效（但 Markdown 有效），显示 Query 的错误信息
  finalOutputText = pubmedQuery;
}

// --- Part 4: 返回最终组合的文本 ---
// 以 Chat Trigger 期望的格式返回
return {
  json: {
    text: finalOutputText
  }
};

// --- Get Output Filename from the PREVIOUS Execute Command Node ---
let markdownFilename = null; // Initialize filename variable

try {
  // Get the input for THIS node, which is the output of the previous node ('生成information.md')
  const previousNodeOutput = $input.first(); // Use .first() to get the single item output

  // Check if the previous node's output and its stdout exist
  if (previousNodeOutput && previousNodeOutput.json && previousNodeOutput.json.stdout) {
    const stdoutText = previousNodeOutput.json.stdout;

    // --- Extraction Logic ---
    // Use a regular expression to find the filename matching the specific pattern:
    // retrieved_issns(YYYYMMDD_HHMMSS)_information.md
    // \d{8} matches exactly 8 digits (YYYYMMDD)
    // \d{6} matches exactly 6 digits (HHMMSS)
    // Parentheses and dot are escaped with backslashes \
    const regex = /(retrieved_issns\(\d{8}_\d{6}\)_information\.md)/g;
    const matches = stdoutText.match(regex);

    if (matches && matches.length > 0) {
      // Assume the relevant filename is the LAST one mentioned if multiple matches occur,
      // though usually the final output filename is mentioned near the end.
      markdownFilename = matches[matches.length - 1];
      console.log(`Extracted filename from stdout: ${markdownFilename}`);
    } else {
      console.warn("Could not find filename pattern 'retrieved_issns(YYYYMMDD_HHMMSS)_information.md' in previous node's stdout:", stdoutText);
      markdownFilename = "Markdown filename pattern not found in stdout";
    }
  } else {
     console.warn("Stdout from the previous node ('生成information.md') is missing or empty.");
     markdownFilename = "Stdout not available from previous node";
  }
} catch (error) {
   console.error("Error processing stdout from previous node ('生成information.md'):", error);
   markdownFilename = "Error processing previous node stdout";
}

// --- Return the extracted filename ---
// Return an object containing the extracted filename
return {
  extractedMarkdownFilename: markdownFilename
};

// 汇总输入中的 NBIB 文本
const items = $input.all();
const texts = [];
for (const it of items) {
  const t = it.json?.data ?? it.json?.body ?? (typeof it.json === 'string' ? it.json : '');
  if (typeof t === 'string' && t.trim()) texts.push(t);
}
const nbibText = texts.join('\n');

// 正则匹配
const isLines = nbibText.match(/^\s*IS\s*-\s*.*$/gm) || [];
const issnRegex = /\b\d{4}-\d{3}[\dXx]\b/g;

const issnSet = new Set();
const electronicSet = new Set();
const printSet = new Set();
const linkingSet = new Set();

for (const line of isLines) {
  const matches = line.match(issnRegex) || [];
  // (Electronic)/(Print)/(Linking) 类型标注
  const type = (line.match(/\(([^)]+)\)\s*$/)?.[1] || '').toLowerCase();

  for (const m of matches) {
    const norm = m.toUpperCase();
    issnSet.add(norm);
    if (type.includes('electronic')) electronicSet.add(norm);
    else if (type.includes('print')) printSet.add(norm);
    else if (type.includes('linking')) linkingSet.add(norm);
  }
}

// 转换为数组，每个ISSN作为单独的item返回
const issnAll = Array.from(issnSet);

// 🔑 关键改动：返回多个item，每个包含一个ISSN
const results = issnAll.map(issn => ({
  json: { issn: issn }
}));

return results;

// 获取上一个节点（Chat Trigger）的输入
// 注意：根据你的 n8n 版本和连接方式，$input.item 或 $json 可能需要调整
// 你可以在左侧 INPUT DATA 面板查看实际传入的数据结构
const userInput = $input.item.json.chatInput; 

// 获取当前日期
const today = new Date();
const year = today.getFullYear();
// 月份是从0开始的，所以要加1，并补零
const month = String(today.getMonth() + 1).padStart(2, '0'); 
// 日期补零
const day = String(today.getDate()).padStart(2, '0');

// 格式化成 YYYY-MM-DD，方便模型理解
const formattedToday = `${year}-${month}-${day}`;

// ★ 关键：准备要传递给下一个节点（Agent）的数据
// 我们将原始的用户输入和计算好的当前日期一起传递
const outputData = {
  originalQuery: userInput, // 原始用户查询
  currentDateInfo: formattedToday // 当前日期字符串
};

// 返回包含这些信息的新 item
// n8n 会自动将其包装在 json 字段下传给下一个节点
return {
  json: outputData 
};

// 初始化保存文件名的数组
const filesToDelete = [];
// 更新节点检查列表，移除已删除的节点
const nodesToCheck = [
  "提取并去重ISSN", "准备CSV", "保存retrieved_issns(YYYYMMDD_HHMMSS).csv", 
  "保存core_query.txt", "生成information.csv", "生成information.md",
  "合并参考文献", "保存综述.MD"  // 添加了生成MD文件的节点
];

// 收集各节点中可能存在的文件名信息
for (const nodeName of nodesToCheck) {
  try {
    const node = $node[nodeName];
    if (!node || !node.json) continue;

    // 检查可能包含文件名的常见字段
    const possibleFields = [
      "csvFilename", "outputFilename", "queryFilename", 
      "filePathToSave", "informationFilename", "finalContentLength"
    ];

    for (const field of possibleFields) {
      if (node.json[field]) {
        const filename = node.json[field];
        // 如果是完整路径，提取文件名部分
        const basename = filename.includes('/') 
          ? filename.substring(filename.lastIndexOf('/') + 1) 
          : filename;

        // 只排除 .docx 文件，所有其他文件都加入删除列表
        if (!filesToDelete.includes(basename) && !basename.endsWith('.docx')) {
          filesToDelete.push(basename);
          console.log(`从节点 ${nodeName} 收集到文件: ${basename}`);
        }
      }
    }
  } catch (error) {
    console.error(`处理节点 ${nodeName} 时出错:`, error);
  }
}

// 添加时间戳模式匹配
const timeStampPatterns = new Set();
for (const filename of filesToDelete) {
  const match = filename.match(/retrieved_issns\((\d{8}_\d{6})\)/);
  if (match && match[1]) {
    timeStampPatterns.add(match[1]);
  }
}

console.log("找到的时间戳模式:", Array.from(timeStampPatterns));

// 构建删除命令
let deleteCommand = "cd /data/pubmed-search && ";

// 如果有特定文件名可以直接删除
if (filesToDelete.length > 0) {
  // 转义文件名中的特殊字符
  const escapedFiles = filesToDelete.map(f => f.replace(/([()])/g, '\\$1')).join(' ');
  deleteCommand += `rm -f ${escapedFiles} && `;
}

// 如果有时间戳模式，添加模式匹配删除
if (timeStampPatterns.size > 0) {
  for (const pattern of timeStampPatterns) {
    // 修改这里：删除所有相关文件，但排除 .docx 文件
    deleteCommand += `find . -type f -name "retrieved_issns(${pattern})*" ! -name "*.docx" -delete && `;
  }
}

// 删除命令末尾的 " && "
deleteCommand = deleteCommand.endsWith(" && ") 
  ? deleteCommand.slice(0, -4) 
  : deleteCommand;

// 如果没有任何删除操作，添加一个空操作
if (deleteCommand === "cd /data/pubmed-search") {
  deleteCommand += " && echo 'No files to delete'";
}

// 返回文件列表和删除命令
return {
  filesToDelete,
  timeStampPatterns: Array.from(timeStampPatterns),
  deleteCommand
};

// --- Get Chat Input ---
// Get the input item from the 'When chat message received' node
const chatInputItem = $('When chat message received').first();
// Access the chatInput field from the JSON data of that item
const chatInputValue = chatInputItem.json.chatInput;
// Explicitly convert the value to a string data type.
const chatInputText = String(chatInputValue);

// --- Get Output Filename from Execute Command Stdout ---
let informationFilename = null; // Initialize filename variable

try {
  // Get the output of the '生成information.csv' node (the Execute Command node)
  // Use .first() as it usually outputs one item
  // Note: We access the *input* to this Code node, which is the output of the previous node.
  const executeCmdItem = $input.first(); // Get the input data for THIS node

  // Check if the command node output and its stdout exist
  if (executeCmdItem && executeCmdItem.json && executeCmdItem.json.stdout) {
    const stdoutText = executeCmdItem.json.stdout;

    // Use a regular expression to find the filename ending with '_information.csv'
    // This regex looks for a path-like structure ending in '_information.csv'
    // It captures the filename part (characters not being '/' or whitespace) before the suffix.
    const regex = /([^/\s]+_information\.csv)/g;

    const matchResult = stdoutText.match(regex);

    // If a match is found, extract the *last* occurrence, as stdout might mention it multiple times
    if (matchResult && matchResult.length > 0) {
      // matchResult is an array of all matches, e.g., ["file1_information.csv", "file2_information.csv"]
      // We usually want the last one mentioned in the stdout.
      informationFilename = matchResult[matchResult.length - 1];
    } else {
       console.warn("Could not find information filename pattern in stdout:", stdoutText);
       informationFilename = "Filename not found in stdout"; // Set a default/error value
    }
  } else {
     console.warn("Stdout from previous node ('生成information.csv') is missing or empty.");
     informationFilename = "Stdout not available"; // Set a default/error value
  }
} catch (error) {
   console.error("Error processing stdout from previous node ('生成information.csv'):", error);
   informationFilename = "Error processing stdout"; // Set a default/error value
}


// Return the extracted values in an object
return {
  extractedChatInput: chatInputText,
  informationFilename: informationFilename // The filename ending in _information.csv extracted from stdout
};

// === 0. 从「When chat message received」节点拿到最初的检索要求 ===
let originalQuery = '';
try {
  const triggerItem = $('When chat message received').first();
  originalQuery = String(triggerItem.json?.chatInput ?? '').trim();
} catch (err) {
  console.error('[整合摘要] 获取原始检索式失败：', err);
}

// === 1. 汇总各文献信息（修改为处理原生文献数据） ===
const items = $('Process Article Data1').all();
let combinedContent = '';
let articleCount = 0;
const processingErrors = [];

for (let i = 0; i < items.length; i++) {
  const articleData = items[i]?.json;

  // 检查是否有有效的文献文本数据
  if (!articleData?.articleText || typeof articleData.articleText !== 'string') {
    processingErrors.push({ index: i + 1, error: '缺少 articleText 字段或不是字符串' });
    continue;
  }

  // 直接使用格式化好的文献文本
  combinedContent += (articleCount ? '\n' : '') + articleData.articleText;
  articleCount++;
}

// === 2. 生成头部信息（含检索要求） ===
const today = new Date().toISOString().slice(0, 10);
let header = `# 医学文献综述 (${today})\n`;
header += `检索要求：${originalQuery || '（未能获取）'}\n`;
header += `本次共检索到 ${articleCount} 篇相关文献。\n\n`;

const finalContent = header + combinedContent;

// === 3. 向下游返回数据 ===
return [
  {
    json: {
      combined_summary: finalContent,        // 供下游综述生成使用的完整文献信息
      original_query: originalQuery,         // 最早聊天里的检索要求
      totalArticlesInput: items.length,
      articlesSuccessfullyProcessed: articleCount,
      articlesFailedToProcess: processingErrors.length,
      processingErrorDetails: processingErrors
    }
  }
];

// Get the output from the previous agent node
const agentOutput = $input.item.json.output || "";

// Check if the output contains any of the filter parameters
const containsFilterParams = [
  "cas-zones",
  "if-min",
  "if-max",
  "jcr-zones"
].some(param => agentOutput.includes(param));

// If any filter parameters are found, return the original output
// Otherwise, return an empty string
if (containsFilterParams) {
  return {
    json: {
      output: agentOutput
    }
  };
} else {
  return {
    json: {
      output: ""
    }
  };
}

// 获取所有文献数据
const items = $('Process Article Data1').all();
const references = [];

for (let i = 0; i < items.length; i++) {
  const article = items[i]?.json;

  if (!article) continue;

  // 提取作者信息并格式化
  let authorString = '';
  if (article.authors && article.authors !== 'N/A') {
    // 第一作者
    const firstAuthor = article.authors;
    authorString = firstAuthor;

    // 如果有通讯作者且不同于第一作者
    if (article.correspondingAuthor && 
        article.correspondingAuthor !== 'N/A' && 
        article.correspondingAuthor !== firstAuthor) {
      // 简化处理：如果有多个作者，添加 et al.
      authorString += ', et al.';
    }
  } else {
    authorString = 'Anonymous';
  }

  // 格式化标题（首字母大写，其余小写）
  let formattedTitle = article.title || 'No title available';
  if (formattedTitle && formattedTitle !== 'N/A') {
    formattedTitle = formattedTitle.charAt(0).toUpperCase() + formattedTitle.slice(1).toLowerCase();
  }

  // 格式化期刊名称（需要转换为标准缩写，这里简化处理）
  let journalName = article.journal || 'Unknown Journal';
  if (journalName && journalName !== 'N/A') {
    // 简化的期刊名称缩写处理
    journalName = journalName
      .replace(/Journal of/g, 'J')
      .replace(/American Journal of/g, 'Am J')
      .replace(/European Journal of/g, 'Eur J')
      .replace(/International Journal of/g, 'Int J')
      .replace(/British Journal of/g, 'Br J')
      .replace(/The /g, '')
      .trim();
  }

  // 格式化发表日期
  let publicationInfo = '';
  if (article.publicationDate && article.publicationDate !== 'N/A') {
    const pubDate = article.publicationDate;
    if (pubDate.match(/^\d{4}$/)) {
      // 只有年份
      publicationInfo = `${pubDate};`;
    } else if (pubDate.match(/^\d{4}-\d{2}$/)) {
      // 年份-月份
      publicationInfo = `${pubDate.split('-')[0]};`;
    } else if (pubDate.match(/^\d{4}-\d{2}-\d{2}$/)) {
      // 完整日期
      publicationInfo = `${pubDate.split('-')[0]};`;
    } else {
      publicationInfo = `${pubDate};`;
    }
  } else {
    publicationInfo = 'Unknown year;';
  }

  // PMID信息
  const pmid = article.pmid && article.pmid !== 'N/A' ? article.pmid : 'Unknown';

  // 构建AMA格式的参考文献条目
  const referenceEntry = `${i + 1}. ${authorString}. ${formattedTitle}. *${journalName}*. ${publicationInfo} PMID: ${pmid}`;

  references.push(referenceEntry);
}

// 生成完整的参考文献列表
const referencesSection = '## 参考文献\n\n' + references.join('\n\n');

// 返回结果
return {
  json: {
    referencesSection: referencesSection,
    totalReferences: references.length,
    // 同时传递原有的数据给下游
    combined_summary: $input.item.json.combined_summary,
    original_query: $input.item.json.original_query,
    totalArticlesInput: $input.item.json.totalArticlesInput,
    articlesSuccessfullyProcessed: $input.item.json.articlesSuccessfullyProcessed
  }
};

// 获取AI生成的综述内容（来自综述写作agent）
const reviewContent = $input.item.json.output || "";

// 获取预生成的参考文献列表（来自生成AMA格式参考文献节点）
const referencesSection = $node['生成AMA格式参考文献']?.json?.referencesSection || "";

// 合并内容：综述正文 + 参考文献
let finalContent = reviewContent;

// 确保综述内容以换行结束
if (!finalContent.endsWith('\n')) {
  finalContent += '\n';
}

// 添加两个换行符作为分隔
finalContent += '\n';

// 添加参考文献部分
finalContent += referencesSection;

console.log(`[合并参考文献] 综述内容长度: ${reviewContent.length}`);
console.log(`[合并参考文献] 参考文献长度: ${referencesSection.length}`);
console.log(`[合并参考文献] 最终内容长度: ${finalContent.length}`);

// 生成文件名和路径信息
const now = new Date();
const year = now.getFullYear();
const month = String(now.getMonth() + 1).padStart(2, '0');
const day = String(now.getDate()).padStart(2, '0');
const hours = String(now.getHours()).padStart(2, '0');
const minutes = String(now.getMinutes()).padStart(2, '0');
const seconds = String(now.getSeconds()).padStart(2, '0');
const timestamp = `${year}${month}${day}_${hours}${minutes}${seconds}`;

const filename = `retrieved_issns(${timestamp})_review.md`;
const filePath = `/data/pubmed-search/${filename}`;

// 转换为二进制数据
const base64Data = Buffer.from(finalContent, 'utf8').toString('base64');

const binaryData = {
  data: base64Data,
  fileName: filename,
  mimeType: 'text/markdown'
};

// 返回结果
return {
  json: {
    filePathToSave: filePath,
    finalContentLength: finalContent.length,
    referencesIncluded: referencesSection.length > 0
  },
  binary: {
    data: binaryData
  }
};
